import { describe, expect, test } from '@a0n/gnosis/test';
import {
  buildWeatherMeshTaskUnits,
  iterateActiveWeatherMeshUnits,
  stepWeatherMeshNeighbor,
  type WeatherMeshCellLike,
} from './weather-mesh-adapter';

function makeCell(
  li: number,
  oi: number,
  overrides: Partial<WeatherMeshCellLike> = {}
): WeatherMeshCellLike {
  return {
    latIndex: li,
    lonIndex: oi,
    spatialHex64: `cell:${li}:${oi}`,
    centroid: { lat: -90 + li * 0.25, lon: -180 + oi * 0.25 },
    areaWeightBps: 10_000,
    active: true,
    activeReason: 'ocean',
    ...overrides,
  };
}

describe('buildWeatherMeshTaskUnits', () => {
  test('produces a task unit per input cell keyed by spatial hash', async () => {
    const cells = [makeCell(400, 720), makeCell(400, 721), makeCell(401, 720)];
    const units = buildWeatherMeshTaskUnits(cells, {
      hashSpatial: (li, oi) => `cell:${li}:${oi}`,
    });
    expect(units.size).toBe(3);
    expect(units.get('cell:400:720')).toBeDefined();
    expect(units.get('cell:401:720')?.active).toBe(true);
  });

  test('wires 8 spatial neighbors by ID, resolving out-of-set cells via the hash function', async () => {
    const cells = [makeCell(400, 720)];
    const units = buildWeatherMeshTaskUnits(cells, {
      hashSpatial: (li, oi) => `cell:${li}:${oi}`,
    });
    const unit = units.get('cell:400:720')!;
    // All 8 neighbors are outside the input set → resolved via hashSpatial.
    expect(unit.neighbors.n).toBe('cell:401:720');
    expect(unit.neighbors.s).toBe('cell:399:720');
    expect(unit.neighbors.e).toBe('cell:400:721');
    expect(unit.neighbors.w).toBe('cell:400:719');
    expect(unit.neighbors.ne).toBe('cell:401:721');
    expect(unit.neighbors.nw).toBe('cell:401:719');
    expect(unit.neighbors.se).toBe('cell:399:721');
    expect(unit.neighbors.sw).toBe('cell:399:719');
  });

  test('steps neighbors in O(1) via the pre-computed ID table', async () => {
    const cells = [makeCell(400, 720), makeCell(400, 721), makeCell(401, 720)];
    const units = buildWeatherMeshTaskUnits(cells, {
      hashSpatial: (li, oi) => `cell:${li}:${oi}`,
    });
    const center = units.get('cell:400:720')!;
    const east = stepWeatherMeshNeighbor(units, center, 'e');
    const north = stepWeatherMeshNeighbor(units, center, 'n');
    const offSet = stepWeatherMeshNeighbor(units, center, 'w');
    expect(east?.id).toBe('cell:400:721');
    expect(north?.id).toBe('cell:401:720');
    // West neighbor is outside the input set.
    expect(offSet).toBeNull();
  });

  test('wraps eastward at the antimeridian using lonIndexCount', async () => {
    const rightmost = makeCell(360, 1439);
    const units = buildWeatherMeshTaskUnits([rightmost], {
      hashSpatial: (li, oi) => `cell:${li}:${oi}`,
      lonIndexCount: 1440,
    });
    expect(units.get('cell:360:1439')?.neighbors.e).toBe('cell:360:0');
  });

  test('emits temporal neighbors when a hashSpaceTime function and timeIndex are provided', async () => {
    const cell = makeCell(360, 720, { timeIndex: 100 });
    const units = buildWeatherMeshTaskUnits([cell], {
      hashSpatial: (li, oi) => `cell:${li}:${oi}`,
      hashSpaceTime: (li, oi, ti) => `st:${li}:${oi}:${ti}`,
    });
    const unit = units.get('cell:360:720')!;
    expect(unit.neighbors.tPrev).toBe('st:360:720:99');
    expect(unit.neighbors.tNext).toBe('st:360:720:101');
  });

  test('leaves temporal neighbors null when timeIndex is absent', async () => {
    const cell = makeCell(360, 720);
    const units = buildWeatherMeshTaskUnits([cell], {
      hashSpatial: (li, oi) => `cell:${li}:${oi}`,
    });
    const unit = units.get('cell:360:720')!;
    expect(unit.neighbors.tPrev).toBe(null);
    expect(unit.neighbors.tNext).toBe(null);
  });

  test('dormant cells get zero weight', async () => {
    const cell = makeCell(360, 720, {
      active: false,
      areaWeightBps: 9500,
      activeReason: 'none',
    });
    const units = buildWeatherMeshTaskUnits([cell], {
      hashSpatial: (li, oi) => `cell:${li}:${oi}`,
    });
    const unit = units.get('cell:360:720')!;
    expect(unit.active).toBe(false);
    expect(unit.weight).toBe(0);
  });
});

describe('iterateActiveWeatherMeshUnits', () => {
  test('returns only active units in deterministic grid order', async () => {
    const cells = [
      makeCell(401, 721, { active: true }),
      makeCell(400, 720, { active: true }),
      makeCell(400, 721, { active: false }),
    ];
    const units = buildWeatherMeshTaskUnits(cells, {
      hashSpatial: (li, oi) => `cell:${li}:${oi}`,
    });
    const active = iterateActiveWeatherMeshUnits(units);
    expect(active.map((u) => u.id)).toEqual(['cell:400:720', 'cell:401:721']);
  });
});

describe('determinism', () => {
  test('identical inputs produce identical maps', async () => {
    const cells = [makeCell(200, 100), makeCell(201, 100), makeCell(200, 101)];
    const left = buildWeatherMeshTaskUnits(cells, {
      hashSpatial: (li, oi) => `cell:${li}:${oi}`,
    });
    const right = buildWeatherMeshTaskUnits(cells, {
      hashSpatial: (li, oi) => `cell:${li}:${oi}`,
    });
    expect(Array.from(left.keys()).sort()).toEqual(Array.from(right.keys()).sort());
    const leftCenter = left.get('cell:200:100')!;
    const rightCenter = right.get('cell:200:100')!;
    expect(leftCenter.neighbors).toEqual(rightCenter.neighbors);
  });
});
